value.string:
{
 "$schema": "http://json-schema.org/draft-07/schema#",
 "type": "object",
 "description": "Schema information for a portal type, including all available columns and their properties",
 "properties": {
 "portal_type": {
 "type": "string",
 "description": "The portal type ID that this schema applies to"
 },
 "columns": {
 "type": "object",
 "description": "Dictionary mapping column titles to their properties",
 "patternProperties": {
 "^.*$": {
 "type": "object",
 "description": "Properties for a specific column",
 "properties": {
 "default": {
 "type": "boolean",
 "description": "Whether this column appears by default in listings"
 },
 "filterable": {
 "type": "boolean",
 "description": "Whether this column can be used for filtering and sorting"
 }
 },
 "additionalProperties": true
 }
 }
 }
 },
 "required": ["portal_type", "columns"],
 "additionalProperties": false
 }

{\n
  "additionalProperties": false,\n
  "required": [\n
    "portal_type_id"\n
  ],\n
  "type": "object",\n
  "properties": {\n
    "portal_type_id": {\n
      "type": "string",\n
      "description": "The ID/name of the portal type to get schema for.\\n\\nUse MCP_listPortalTypes first to see all available portal type IDs and their descriptions.\\n\\nExamples: \'Task Report\', \'Sale Order\', \'Person\'."\n
    }\n
  }\n
}\n
